// Leveling narrative template for SAP engineers moving between FAANGs
// Structure your accomplishments around these dimensions

const narrativeTemplate = {
  scope: {
    title: "What I Owned",
    sapExample: "Led data architecture for S/4HANA migration",
    faangFrame: "Designed distributed data pipeline processing 500TB across 12 regions",
  },
  ambiguity: {
    title: "How I Navigated Uncertainty",
    sapExample: "Customer requirements changed mid-migration",
    faangFrame: "Redesigned system architecture with 3-week sprint when regulatory requirements shifted",
  },
  influence: {
    title: "How I Aligned Others",
    sapExample: "Got 5 teams to agree on migration timeline",
    faangFrame: "Convinced 5 cross-functional teams to adopt new infrastructure org-wide",
  },
  metrics: {
    title: "Measurable Impact",
    sapExample: "Migration completed under budget",
    faangFrame: "Reduced migration time by 40%, saved $2.3M in operational costs",
  }
};

// Compensation modeling function
// Model your 4-year total comp across different FAANG offers

interface CompOffer {
  base: number;       // Annual base salary
  bonus: number;      // Annual target bonus (% of base)
  signOn: number;     // Sign-on cash bonus
  rsuGrant: number;   // Total RSU grant value at join
  rsuVestSchedule: number[]; // Vesting percentages per year
  annualRefresher: number;   // Expected annual RSU refresher
  stockGrowth: number;       // Assumed annual stock appreciation
}

function projectTotalComp(offer: CompOffer, years: number): number[] {
  const annual: number[] = [];
  let unvestedRsuPool = offer.rsuGrant;
  for (let y = 0; y < years; y++) {
    const vestThisYear = offer.rsuGrant * offer.rsuVestSchedule[y];
    const refresherVest = y > 0 ? offer.annualRefresher * 0.25 : 0; // 4-yr vest
    const stockGain = (offer.rsuGrant - vestThisYear) * offer.stockGrowth;
    annual.push(
      offer.base +
      offer.base * offer.bonus +
      (y === 0 ? offer.signOn : 0) +
      vestThisYear * Math.pow(1 + offer.stockGrowth, y) +
      refresherVest
    );
  }
  return annual;
}
